const express = require('express');
const redis = require('redis');
const twilio = require('twilio');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json());

// Twilio configuration
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID || 'your_account_sid';
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN || 'your_auth_token';
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER || '+1234567890';

const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

// Redis configuration
const redisClient = redis.createClient({
  url: process.env.REDIS_URL || 'redis://localhost:6379'
});

redisClient.on('error', (err) => {
  console.error('Redis Client Error:', err);
});

redisClient.on('connect', () => {
  console.log('Connected to Redis');
});

// Connect to Redis
(async () => {
  await redisClient.connect();
})();

// Constants
const CODE_EXPIRATION_SECONDS = 600; // 10 minutes
const MAX_ATTEMPTS = 10;
const LOCKOUT_DURATION_SECONDS = 1800; // 30 minutes lockout

// Redis key helpers
const getCodeKey = (userId) => `2fa:code:${userId}`;
const getAttemptsKey = (userId) => `2fa:attempts:${userId}`;
const getLockoutKey = (userId) => `2fa:lockout:${userId}`;

// Generate a 6-digit code
function generateCode() {
  const code = Math.floor(100000 + Math.random() * 900000);
  return code.toString();
}

// Send SMS via Twilio
async function sendSMS(phoneNumber, code) {
  try {
    const message = await twilioClient.messages.create({
      body: `Your verification code is: ${code}. It expires in 10 minutes. Do not share this code with anyone.`,
      from: TWILIO_PHONE_NUMBER,
      to: phoneNumber
    });
    console.log(`SMS sent successfully. SID: ${message.sid}`);
    return { success: true, sid: message.sid };
  } catch (error) {
    console.error('Failed to send SMS:', error.message);
    return { success: false, error: error.message };
  }
}

// Middleware to simulate user authentication (replace with real auth)
function authenticateUser(req, res, next) {
  const userId = req.headers['x-user-id'];
  const phoneNumber = req.headers['x-user-phone'];

  if (!userId) {
    return res.status(401).json({
      success: false,
      message: 'Authentication required. Provide x-user-id header.'
    });
  }

  req.userId = userId;
  req.userPhone = phoneNumber;
  next();
}

// POST /2fa/send - Generate and send 2FA code
app.post('/2fa/send', authenticateUser, async (req, res) => {
  try {
    const { userId } = req;
    const phoneNumber = req.body.phoneNumber || req.userPhone;

    if (!phoneNumber) {
      return res.status(400).json({
        success: false,
        message: 'Phone number is required. Provide in body or x-user-phone header.'
      });
    }

    // Check if user is locked out
    const isLockedOut = await redisClient.get(getLockoutKey(userId));
    if (isLockedOut) {
      const ttl = await redisClient.ttl(getLockoutKey(userId));
      return res.status(429).json({
        success: false,
        message: `Account is temporarily locked due to too many failed attempts. Try again in ${Math.ceil(ttl / 60)} minutes.`
      });
    }

    // Generate code
    const code = generateCode();

    // Store code in Redis with 10-minute expiration
    await redisClient.set(getCodeKey(userId), code, { EX: CODE_EXPIRATION_SECONDS });

    // Reset attempts counter
    await redisClient.set(getAttemptsKey(userId), '0', { EX: CODE_EXPIRATION_SECONDS });

    // Send SMS
    const smsResult = await sendSMS(phoneNumber, code);

    if (!smsResult.success) {
      // Clean up Redis keys if SMS fails
      await redisClient.del(getCodeKey(userId));
      await redisClient.del(getAttemptsKey(userId));

      return res.status(500).json({
        success: false,
        message: 'Failed to send verification code. Please try again.'
      });
    }

    // Mask phone number for response
    const maskedPhone = phoneNumber.replace(/(\+?\d{1,3})\d+(\d{4})/, '$1****$2');

    res.status(200).json({
      success: true,
      message: `Verification code sent to ${maskedPhone}`,
      expiresIn: CODE_EXPIRATION_SECONDS,
      maxAttempts: MAX_ATTEMPTS
    });
  } catch (error) {
    console.error('Error in /2fa/send:', error);
    res.status(500).json({
      success: false,
      message: 'Internal server error'
    });
  }
});

