// Middleware to verify session token for protected routes
async function verify2FASession(req, res, next) {
  const token = req.headers['x-session-token'] || req.headers.authorization?.replace('Bearer ', '');

  if (!token) {
    return res.status(401).json({
      success: false,
      message: 'Session token required. Complete 2FA verification first.'
    });
  }

  try {
    const sessionData = await redisClient.get(`session:${token}`);

    if (!sessionData) {
      return res.status(401).json({
        success: false,
        message: 'Invalid or expired session token.'
      });
    }

    const session = JSON.parse(sessionData);
    req.session = session;
    req.userId = session.userId;
    next();
  } catch (error) {
    console.error('Session verification error:', error);
    res.status(500).json({
      success: false,
      message: 'Internal server error'
    });
  }
}

